}

return total;

// 1. Si tenemos la lista en este contexto, la usamos para recalcular el total
  if (Array.isArray(this.frm_lista_coaseguro)) {
    const total = this.frm_lista_coaseguro.reduce((acc, row) => {
      const v = row && row.frm_coaseguro_participacion;
      const n = Number(v);
      return acc + (Number.isFinite(n) ? n : 0);
    }, 0);

    // Cacheamos en window para que el modal lo pueda reutilizar
    window.frm_lista_coaseguro_participacion_total = total;

    // Devuelve como número o string según lo que esperes
    return String(total); // o: return total;
  }

  // 2. Si no tenemos la lista (p. ej. dentro del modal), usamos el caché global
  if (typeof window.frm_lista_coaseguro_participacion_total !== 'undefined') {
    return String(window.frm_lista_coaseguro_participacion_total);
  }

  // 3. Si no hay nada cacheado todavía, devolvemos vacío o 0
  return '0'; // o '' si prefieres mostrar nada

const parseNum = (v) => {
  if (v == null) return null;
  if (typeof v === 'number') return v;

  const n = Number(
    v.toString()
      .trim()
      .replace(/\./g, '')  // quita separadores de miles tipo "1.234,56"
      .replace(',', '.')   // convierte coma decimal en punto
  );

  return Number.isFinite(n) ? n : null;
};

const rawVal       = this.frm_coaseguro_participacion;
const rawRestante  = this.frm_lista_coaseguro_participacion_maximo_dup;
const rawMaxEditar = this.frm_lista_coaseguro_participacion_maximo_editar;

let val       = parseNum(rawVal);
let restante  = parseNum(rawRestante);
let maxEditar = parseNum(rawMaxEditar);

let isEdit      = false;
let maxFromEdit = null;
let inputRef    = null;

// ------- Helper para ver si un contenedor [data-cy="..."] está visible -------
const isContainerVisible = (container) => {
  if (!container) return false;
  const dialog = container.querySelector('div[role="dialog"]');
  if (!dialog) return false;

  // Primero mira el style inline, si no, usa getComputedStyle
  const inlineDisplay = dialog.style && dialog.style.display;
  const display =
