      ? inlineDisplay
      : window.getComputedStyle(dialog).display;

  return display !== 'none';
};

// ---------------- Detectar si estamos en modo EDITAR ----------------
try {
  const editContainer = document.querySelector('[data-cy="modal-edit"]');

  if (editContainer && isContainerVisible(editContainer)) {
    isEdit = true;
