    inputRef = editContainer.querySelector('input[name="frm_coaseguro_participacion"]');
    if (inputRef) {
      if (!inputRef.dataset.maxEditCaptured) {
        inputRef.dataset.maxEditCaptured = '1';

        if (Number.isFinite(maxEditar)) {
          inputRef.dataset.maxEdit = String(maxEditar);
        } else {
          inputRef.dataset.maxEdit = '';
        }
      }

      maxFromEdit = parseNum(inputRef.dataset.maxEdit);
    }
  } else {
    //console.log('Modo detectado: AGREGAR');
  }
} catch (e) {
  //console.warn('Error detectando modal de edición o capturando maxFromEdit:', e);
}

// Normalizar restante
if (!Number.isFinite(restante) || restante < 0) {
  restante = 0;
}

// ---------------- Calcular el máximo permitido ----------------
let max;
if (isEdit) {
  if (Number.isFinite(maxFromEdit)) {
    max = maxFromEdit;
  } else if (Number.isFinite(maxEditar)) {
    max = maxEditar;
  } else {
    max = restante;
  }
} else {
  max = restante;
}

// Si el valor no es numérico, devolvemos lo que haya sin validar
if (!Number.isFinite(val)) {
  return this.frm_coaseguro_participacion ?? null;
}

const fmtNum = (n) => String(n).replace('.', ',');

let invalid = false;
let msg = '';

// ---------------- Lógica de validación ----------------
if (!isEdit && max === 0) {
  invalid = true;
  msg = 'No se pueden registrar más coaseguros porque la participación total ya alcanza el 100%.';
} else if (val < 0 || val > max) {
  invalid = true;
  msg = `La participación ingresada debe estar entre 0 y ${fmtNum(max)}.`;
}

// ------- Helper para obtener el modal ACTIVO (ADD o EDIT) -------
const getVisibleModalRoot = () => {
  const containers = document.querySelectorAll('[data-cy="modal-add"], [data-cy="modal-edit"]');

  for (const container of containers) {
    if (isContainerVisible(container)) {
      return container;
    }
  }

  // Fallback: cualquier modal con display:block
  const anyDialog = document.querySelector(
    'div[role="dialog"].modal.fade.show[style*="display: block"]'
  );
  return anyDialog ? anyDialog.closest('.modal') || anyDialog : document;
};

// ---------------- Pintar el error en el modal ACTIVO ----------------
setTimeout(() => {
  const root = getVisibleModalRoot();

  const input = root.querySelector('input[name="frm_coaseguro_participacion"]');
  const group = input?.closest('.form-group');

  if (!input || !group) {
    //console.warn('No se encontró input o form-group para pintar el error.');
    return;
  }

  let feedback = group.querySelector('.invalid-feedback');
  if (!feedback) {
    feedback = document.createElement('div');
    feedback.className = 'invalid-feedback';
    group.appendChild(feedback);
  }

  input.classList.remove('is-invalid');

  if (invalid) {
    if (!input.classList.contains('is-invalid')) {
      input.classList.add('is-invalid');
    }
    feedback.innerHTML = msg;
  }
}, 200);

// ---------------- Control del valor devuelto ----------------
if (invalid) {
  //console.log('invalid = true, se retorna null para bloquear el guardado.');
  return null;
}

// Si es válido, devolvemos el número
return val;

setTimeout(() => {
  try {
    // Helper: ver si un contenedor [data-cy="modal-xxx"] está visible
    const isContainerVisible = (container) => {
      if (!container) return false;
      const dialog = container.querySelector('div[role="dialog"]');
      if (!dialog) return false;

      const inlineDisplay = dialog.style && dialog.style.display;
      const display =
        inlineDisplay && inlineDisplay.trim() !== ''
          ? inlineDisplay
          : window.getComputedStyle(dialog).display;

      return display !== 'none';
    };

    // 1) Buscar los contenedores de ADD y EDIT
    const containers = document.querySelectorAll(
      '[data-cy="modal-add"], [data-cy="modal-edit"]'
    );

    let activeContainer = null;
    for (const c of containers) {
      if (isContainerVisible(c)) {
        activeContainer = c;
        break;
      }
    }

    // Si no encontramos una modal visible, no hacemos nada
    if (!activeContainer) return;

    // 2) Desde el contenedor activo, buscamos el .modal-dialog
    const modalDialog = activeContainer.querySelector('.modal-dialog');
    if (!modalDialog) return;

    const footer = modalDialog.querySelector('.modal-footer');
    if (!footer) return;

    const aceptarBtn = footer.querySelector('button.btn.btn-primary');
    if (!aceptarBtn) return;

    console.log('🟦 Botón Aceptar detectado en modal activa:', aceptarBtn);

    // Función helper para saber si hay algún error visible en ESTA modal
    const tieneErroresVisibles = () => {
      const invalids = Array.from(
        modalDialog.querySelectorAll('.invalid-feedback')
      );

      return invalids.some((div) => {
        const style = window.getComputedStyle(div);
        const visible =
          style.display !== 'none' &&
          style.visibility !== 'hidden' &&
          style.opacity !== '0';

        const msgRaw = (div.textContent || '').trim();

        return visible && msgRaw; // cualquier mensaje visible con texto
      });
    };

    const hayErrorVisible = tieneErroresVisibles();

    // 🔐 Estado visual del botón
    aceptarBtn.disabled = hayErrorVisible;
    aceptarBtn.classList.toggle('disabled', hayErrorVisible);

    // Parche extra: interceptar el click y bloquearlo si hay errores
    if (!aceptarBtn._coaseguroGuard) {
      aceptarBtn._coaseguroGuard = true;

      aceptarBtn.addEventListener(
        'click',
        (e) => {
          const bloqueaAhora = tieneErroresVisibles();

          if (bloqueaAhora) {
            e.stopImmediatePropagation?.();
            e.stopPropagation();
            e.preventDefault();
            return false;
          }
        },
        true // captura, para adelantarnos al handler de Vue
      );
    }
  } catch (err) {
    //console.error('Error en controlBotonAceptarCoaseguro:', err);
  }
}, 0);

return '';

const raw = this.frm_coaseguro_participacion;
  if (raw == null || raw === "") return "";

  let s = String(raw).trim().replace(/\s/g, "").replace(/%/g, "");

  s = s.replace(",", ".");

  s = s.replace(/[^0-9.-]/g, "");

  const n = Number(s);
  if (!Number.isFinite(n)) return "";

  return `${n}%`;

const rows = this.frm_lista_coaseguro || [];
if (!Array.isArray(rows)) return "";

const counts = new Map();

for (const r of rows) {
  const compania_nombre = (r.frm_coaseguro_compania_coaseguradora_nombre || "")
    .trim()
    .toLowerCase();

  if (!compania_nombre) continue;

  counts.set(compania_nombre, (counts.get(compania_nombre) || 0) + 1);
}

const duplicates = [];
for (const [compania_nombre, n] of counts.entries()) {
  if (n > 1) duplicates.push(compania_nombre);
}

return duplicates.join(", "); // ejemplo: "a@x.com, b@y.com"

const rows = this.frm_lista_coaseguro || [];

if (!Array.isArray(rows)) return "false";

const seen = new Set();

for (const r of rows) {
  const compania_nombre = (r.frm_coaseguro_compania_coaseguradora_nombre || "")
    .trim();

  if (!compania_nombre) continue; // ignora vacíos o null

  if (seen.has(compania_nombre)) return "true"; // duplicado encontrado
  seen.add(compania_nombre);
}

return "false";

screens.custom_css:
[selector="text-invalid"] {
  color: #EC5962;
  font-size: .875em;
}

[selector="list-record-4"] .data-table {
  display: flex;
  flex-direction: column;
}

[selector="list-record-4"] .data-table > .row.mb-2.ml-0.mr-0 {
  order: 1;
}

[selector="list-record-4"] .data-table > .d-flex.justify-content-between.align-items-center {
  order: 2;
  width: 100%;
  justify-content: flex-end !important;
  margin: .25rem 0 .5rem;
}

[selector="list-record-4"] .data-table > .d-flex.justify-content-between.align-items-center > .col {
  flex: 0 0 auto;
  max-width: unset;
}
[selector="list-record-4"] .data-table > .d-flex.justify-content-between.align-items-center > .col.text-left {
  display: none;
}
[selector="list-record-4"] .data-table > .d-flex.justify-content-between.align-items-center > .col.text-right {
  display: block;
}

[selector="list-record-4"] .data-table > .d-flex [data-cy="add-row"].btn {
  font-weight: 600;
  border-radius: 6px;
  padding: .35rem .9rem;
  box-shadow: 0 2px 8px rgba(0,0,0,.08);
  margin: 0 -10px 10px 0;
}

[selector="list-record-4"] .data-table > table.record-list-table-secondary {
  order: 3;
}

@media (min-width: 576px) {
  [selector="list-record-4"] .data-table > .d-flex.justify-content-between.align-items-center {
    margin-bottom: .75rem;
  }
}


[selector="list-record-4"] table.record-list-table-secondary thead th.text-right > div {
  position: relative;
  color: transparent; /* oculta el texto original */
}
[selector="list-record-4"] table.record-list-table-secondary thead th.text-right > div::after {
  content: "Acciones";
  position: absolute;
  right: 0; left: auto; top: 0;
  color: #2c3e50;
  font-weight: 600;
  text-align: right;
  width: 100%;
}

/* ================================
   2) Colores de íconos Editar/Eliminar
   (SVG embebidos como )
================================ */
/* EDITAR -> Azul Zurich (#0f4c81) */
[selector="list-record-4"] td[aria-colindex="3"] .actions [title="Editar"] img{
  transition: filter .15s ease, transform .12s ease;
  filter: invert(17%) sepia(22%) saturate(2557%) hue-rotate(171deg) brightness(92%) contrast(92%);
}
[selector="list-record-4"] td[aria-colindex="3"] .actions [title="Editar"]:hover img{
  filter: invert(13%) sepia(27%) saturate(2412%) hue-rotate(173deg) brightness(80%) contrast(95%);
  transform: translateY(-1px);
}

/* ELIMINAR -> Rojo (#dc2626) */
[selector="list-record-4"] td[aria-colindex="3"] .actions [title="Eliminar"] img{
  transition: filter .15s ease, transform .12s ease;
  filter: invert(14%) sepia(90%) saturate(6268%) hue-rotate(356deg) brightness(90%) contrast(104%);
}
[selector="list-record-4"] td[aria-colindex="3"] .actions [title="Eliminar"]:hover img{
  filter: invert(11%) sepia(93%) saturate(5530%) hue-rotate(355deg) brightness(70%) contrast(110%);
  transform: translateY(-1px);
}

/* Accesibilidad: micro-resalte al enfocar con teclado */
[selector="list-record-4"] td[aria-colindex="3"] .actions .btn:focus img{
  outline: none;
  filter: drop-shadow(0 0 0.25rem rgba(15,76,129,.35));
}

/* ================================
   3) POPOVER dinámico anclado al grupo de acciones
   (reemplaza tu margin-top fijo)
================================ */

/* Asegura que el popover pueda “salirse” visualmente de la celda */
[selector="list-record-4"] td[aria-colindex="3"]{
  overflow: visible; /* para que no lo recorte la celda */
}

/* El contenedor de botones será el ancla de posicionamiento */
[selector="list-record-4"] td[aria-colindex="3"] .actions{
  position: relative; /* ancla */
  z-index: 1;
}

/* Popover colocado respecto a .actions, sin offsets mágicos */
[selector="list-record-4"] td[aria-colindex="3"] .actions .popover-content{
  position: absolute;
  right: 0;
  /* —> mostrar ARRIBA de los botones (no abajo) */
  top: auto;
  bottom: calc(100% + 8px);
  z-index: 2000;

  margin-top: 0 !important;
  background: #fff;
  border: 1px solid #e5e7eb;
  border-radius: 8px;
  padding: 10px 12px;
  box-shadow: 0 10px 24px rgba(0,0,0,.12);
  width: max-content;
  max-width: clamp(220px, 40vw, 320px);
}

/* Flechita del popover (opcional) */
[selector="list-record-4"] td[aria-colindex="3"] .actions .popover-content::before{
  content: "";
  position: absolute;
  bottom: -6px;
  right: 14px;
  border-width: 6px;
  border-style: solid;
  border-color: #fff transparent transparent transparent;
  filter: drop-shadow(0 1px 0 #e5e7eb);
}

/* Variante para mostrarlo hacia arriba cuando no hay espacio abajo */
[selector="list-record-4"] td[aria-colindex="3"] .actions .popover-content.popover--top{
  top: auto;
  bottom: calc(100% + 8px);
}
[selector="list-record-4"] td[aria-colindex="3"] .actions .popover-content.popover--top::before{
  top: auto;
  bottom: -6px;
  border-color: #fff transparent transparent transparent;
  filter: drop-shadow(0 1px 0 #e5e7eb);
}


/* Limitar el alcance a tu tabla */
[selector="list-record-4"] .actions .popover-content p,
[selector="list-record-4"] .actions .popover-content .btn {
  position: relative;
  /* Oculta el texto original sin romper layout */
  color: transparent !important;
  font-size: 0 !important;
}

/* Texto del mensaje */
[selector="list-record-4"] .actions .popover-content p::after {
  content: "¿Confirmas que deseas eliminar este registro?";
  font-size: 0.95rem;
  color: #111827;
  line-height: 1.35;
  display: block;
}

/* Botón CANCEL → Cancelar */
[selector="list-record-4"] .actions .popover-content .btn.btn-light::after {
  content: "Cancelar";
  font-size: 0.875rem;
  color: #374151;
}

/* Botón DELETE → Eliminar */
[selector="list-record-4"] .actions .popover-content .btn.btn-danger::after {
  content: "Eliminar";
  font-size: 0.875rem;
  color: #fff;
}

/* Mantener clics y foco normal (el pseudo no captura eventos) */
[selector="list-record-4"] .actions .popover-content p::after,
[selector="list-record-4"] .actions .popover-content .btn::after {
  pointer-events: none;
}

[selector="list-record-4"] .data-table.max-rows [data-cy="add-row"].btn {
  display: none !important;
}

/* Ocultar botón "Eliminar" solo en la primera fila */
[selector="list-record-4"]
table.record-list-table-secondary tbody tr:first-child
td[aria-colindex="3"] .actions [title="Eliminar"] {
  display: none !important;
}
